import React from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';

const navConfig = {
  customer: [
    { path: '/shop', icon: '🛍️', label: 'Cửa hàng' },
    { path: '/cart', icon: '🛒', label: 'Giỏ hàng' },
    { path: '/my-orders', icon: '📦', label: 'Đơn hàng của tôi' },
    { path: '/profile', icon: '👤', label: 'Hồ sơ' },
  ],
  warehouse: [
    { path: '/warehouse', icon: '🏭', label: 'Đơn cần xử lý' },
    { path: '/warehouse/inventory', icon: '📊', label: 'Kho hàng' },
  ],
  delivery: [
    { path: '/delivery', icon: '🚚', label: 'Đơn giao hàng' },
  ],
  admin: [
    { path: '/admin/dashboard', icon: '📈', label: 'Dashboard' },
    { path: '/admin/orders', icon: '📋', label: 'Quản lý đơn hàng' },
    { path: '/admin/products', icon: '🛍️', label: 'Sản phẩm' },
    { path: '/admin/users', icon: '👥', label: 'Người dùng' },
    { path: '/admin/inventory', icon: '📦', label: 'Kho hàng' },
    { path: '/admin/revenue', icon: '💰', label: 'Doanh thu' },
  ],
};

const roleLabel = {
  customer: 'Khách hàng',
  warehouse: 'Nhân viên kho',
  delivery: 'Nhân viên giao hàng',
  admin: 'Quản trị viên',
};

export default function Sidebar() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const { pathname } = useLocation();

  if (!user) return null;
  const navItems = navConfig[user.role] || [];

  return (
    <aside className="sidebar">
      <div className="sidebar-logo">
        <h2>⚡ FulFillPro</h2>
        <span>Order Fulfillment System</span>
      </div>
      <nav className="sidebar-nav">
        {navItems.map(item => (
          <div
            key={item.path}
            className={`nav-item ${pathname.startsWith(item.path) ? 'active' : ''}`}
            onClick={() => navigate(item.path)}
          >
            <span className="icon">{item.icon}</span>
            {item.label}
          </div>
        ))}
      </nav>
      <div className="sidebar-footer">
        <div className="user-chip">
          <div className="avatar">{user.fullName?.[0]?.toUpperCase()}</div>
          <div className="user-info">
            <div className="user-name">{user.fullName}</div>
            <div className="user-role">{roleLabel[user.role]}</div>
          </div>
        </div>
        <button
          className="btn btn-secondary btn-sm"
          style={{ width: '100%', marginTop: 8, justifyContent: 'center' }}
          onClick={logout}
        >
          🚪 Đăng xuất
        </button>
      </div>
    </aside>
  );
}
